AgentTwinControl::KindEnum AgentTwinControl::toKindEnum(const utility::string_t& value) const
{
    
    if (value == utility::conversions::to_string_t("navigation_command")) {
        return KindEnum::NAVIGATION_COMMAND;
    }
    
    if (value == utility::conversions::to_string_t("controller_policy_execute")) {
        return KindEnum::CONTROLLER_POLICY_EXECUTE;
    }
    
    if (value == utility::conversions::to_string_t("observe_latest_frame")) {
        return KindEnum::OBSERVE_LATEST_FRAME;
    }
    
    if (value == utility::conversions::to_string_t("stop_navigation")) {
        return KindEnum::STOP_NAVIGATION;
    }
    
    if (value == utility::conversions::to_string_t("twin_motion_action")) {
        return KindEnum::TWIN_MOTION_ACTION;
    }
    
    if (value == utility::conversions::to_string_t("joint_control")) {
        return KindEnum::JOINT_CONTROL;
    }
    
    if (value == utility::conversions::to_string_t("movement_plan_from_prompt")) {
        return KindEnum::MOVEMENT_PLAN_FROM_PROMPT;
    }
    
    if (value == utility::conversions::to_string_t("end_effector_target")) {
        return KindEnum::END_EFFECTOR_TARGET;
    }
    
    throw std::invalid_argument("Invalid value for conversion to KindEnum");
}


const utility::string_t AgentTwinControl::fromKindEnum(const KindEnum value) const
{
    switch(value)
    {
        
        case KindEnum::NAVIGATION_COMMAND: return utility::conversions::to_string_t("navigation_command");
        
        case KindEnum::CONTROLLER_POLICY_EXECUTE: return utility::conversions::to_string_t("controller_policy_execute");
        
        case KindEnum::OBSERVE_LATEST_FRAME: return utility::conversions::to_string_t("observe_latest_frame");
        
        case KindEnum::STOP_NAVIGATION: return utility::conversions::to_string_t("stop_navigation");
        
        case KindEnum::TWIN_MOTION_ACTION: return utility::conversions::to_string_t("twin_motion_action");
        
        case KindEnum::JOINT_CONTROL: return utility::conversions::to_string_t("joint_control");
        
        case KindEnum::MOVEMENT_PLAN_FROM_PROMPT: return utility::conversions::to_string_t("movement_plan_from_prompt");
        
        case KindEnum::END_EFFECTOR_TARGET: return utility::conversions::to_string_t("end_effector_target");
        
    }
}

AgentTwinControl::ReadinessEnum AgentTwinControl::toReadinessEnum(const utility::string_t& value) const
{
    
    if (value == utility::conversions::to_string_t("ready")) {
        return ReadinessEnum::READY;
    }
    
    if (value == utility::conversions::to_string_t("needs_setup")) {
        return ReadinessEnum::NEEDS_SETUP;
    }
    
    if (value == utility::conversions::to_string_t("preview_only")) {
        return ReadinessEnum::PREVIEW_ONLY;
    }
    
    if (value == utility::conversions::to_string_t("unavailable")) {
        return ReadinessEnum::UNAVAILABLE;
    }
    
    throw std::invalid_argument("Invalid value for conversion to ReadinessEnum");
}


const utility::string_t AgentTwinControl::fromReadinessEnum(const ReadinessEnum value) const
{
    switch(value)
    {
        
        case ReadinessEnum::READY: return utility::conversions::to_string_t("ready");
        
        case ReadinessEnum::NEEDS_SETUP: return utility::conversions::to_string_t("needs_setup");
        
        case ReadinessEnum::PREVIEW_ONLY: return utility::conversions::to_string_t("preview_only");
        
        case ReadinessEnum::UNAVAILABLE: return utility::conversions::to_string_t("unavailable");
        
    }
}


